#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e3+5;
CI dx[]={1,0,-1,0,1,1,-1,-1},dy[]={0,1,0,-1,-1,1,-1,1};
int n,m,vis[MAXN][MAXN],ans=0;
char a[MAXN][MAXN];
void dfs(int now_x,int now_y)
{
	FOR(i,0,7)
	{
		int new_x=now_x+dx[i];
		int new_y=now_y+dy[i];
		if (vis[new_x][new_y]==false&& a[new_x][new_y]=='W')
		{
			vis[new_x][new_y]=true;
			dfs(new_x,new_y);
		}
	}
}
signed main(void)
{
	//freopen("Lake Counting S.in","r",stdin);
	//freopen("Lake Counting S.out","w",stdout);
	cli(vis);
	n=read(),m=read();
	FOR(i,1,n) 
	{
		FOR(j,1,m) 
		{
			cin>>a[i][j];
			vis[i][j]=0;
		}
	}
	FOR(i,1,n) 
	{
		FOR(j,1,m) 
		{
			if(a[i][j]=='W'&&vis[i][j]==0)
			{
				dfs(i,j);
				++ans;
			}
		}
	}
	write(ans);
	return false;
}
